// Calculate day of year, week number, and learning phase per subscriber
const now = new Date();

// Day of year
const start = new Date(now.getFullYear(), 0, 0);
const diff = now - start;
const oneDay = 86400000;
const dayOfYear = Math.floor(diff / oneDay);

// Week number
const weekNumber = Math.ceil(dayOfYear / 7);

const results = [];

for (const item of $input.all()) {
  const subscribedDate = new Date(item.json['Subscribed Date'] || now);
  const subscribedDays = Math.floor((now - subscribedDate) / oneDay);

  // Determine learning phase
  let phase = 'Beginner';
  if (subscribedDays > 90) {
    phase = 'Advanced';
  } else if (subscribedDays > 30) {
    phase = 'Intermediate';
  }

  results.push({
    json: {
      ...item.json,
      dayOfYear,
      weekNumber,
      subscribedDays,
      phase
    }
  });
}

return results;

// Get subscribers (from previous node)
const subscribers = $('Calculate Day, Week & Phase').all();

// Get content library (from input - Fetch Content Library node)
const contentItems = $input.all();

const results = [];

for (const subscriber of subscribers) {
  const interest = (subscriber.json['Topic Interest'] || '').toLowerCase();
  const phase = subscriber.json['phase'] || 'Beginner';
  const dayOfYear = subscriber.json['dayOfYear'] || 1;

  // Score and match lessons
  let bestLesson = null;
  let bestScore = -1;

  for (const content of contentItems) {
    let score = 0;
    const category = (content.json['Category'] || '').toLowerCase();
    const lessonPhase = (content.json['Phase'] || '').toLowerCase();

    if (category.includes(interest) || interest.includes(category)) score += 3;
    if (lessonPhase === phase.toLowerCase()) score += 2;

    if (score > bestScore) {
      bestScore = score;
      bestLesson = content.json;
    }
  }

  // Fallback by day index
  if (!bestLesson && contentItems.length > 0) {
    bestLesson = contentItems[dayOfYear % contentItems.length].json;
  }

  results.push({
    json: {
      name: subscriber.json['Name'],
      email: subscriber.json['Email'],
      topicInterest: subscriber.json['Topic Interest'],
      phase: subscriber.json['phase'],
      dayOfYear: subscriber.json['dayOfYear'],
      weekNumber: subscriber.json['weekNumber'],
      subscribedDays: subscriber.json['subscribedDays'],
      lessonTitle: bestLesson?.['Lesson Title'] || 'Daily Skill Tip',
      lessonCategory: bestLesson?.['Category'] || 'Career Growth',
      lessonRawContent: bestLesson?.['Raw Content'] || '',
      resourceLink: bestLesson?.['Resource Link'] || 'https://n8n.io'
    }
  });
}

return results;

